  "platforms": "windows10",
  "technologies": "mdm",
  "description": "Added: WUfB | Scheduled Install Day = Everyday, WHfB | Use Passport For Work (User) true, Virtualization Based Technology | Hypervisor Enforced Code Integrity (Enabled with UEFI lock), Require UEFI Memory Attributes Table Require UEFI Memory Attributes Table, Admin Templates | System | Power Management | Sleep Settings | Allow standby states (S1-S3) when sleeping (on battery), Windows Components > BitLocker Drive Encryption > Allow enhanced PINs for startup, Defender Security Intelligence Updates\nModified: Allow Shared User App Data = False, Local Policies Security Options | Interactive Logon Do Not Display Last Signed In to Enabled (username will not be shown), Object Access Audit Filtering Platform Connection to Success+Failure, Object Access Audit Filtering Platform Packet Drop to Success+Failure, Accounts Block Microsoft Accounts to Users can't add or log on with Microsoft accounts, Device Lock | Min Device PW Length = 14\nRemoved: Accounts | Allow Adding Non MSFT Accounts Manually",
  "templateReference": {
    "templateDisplayVersion": null,
    "templateDisplayName": null,
    "templateId": "",
    "templateFamily": "none"
  },
  "name": "PAW-Global-{PAWCSMVersion}-Windows-11-above-System-Hardening-Device-SettingsCatalog"
}
'@
    }
)

# -- Reusable-setting ID resolution -------------------------------------------
# configurationPolicies that reference reusable settings embed the source-tenant
# GUID. We pre-scan all configPolicy JSONs to collect those GUIDs, then after
# creating each reusable setting we fill them in with the new tenant's ID.
$reusableIdMap   = @{}   # oldGuid -> newGuid (populated during the loop)
$reusableGuidPat = [regex]'deviceManagementConfigurationReferenceSettingValue[\s\S]{0,500}?"value":\s*"([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})"'
foreach ($def in ($policyDefs | Where-Object { $_.Type -eq 'configPolicy' })) {
    $reusableGuidPat.Matches($def.Json) | ForEach-Object {
        $reusableIdMap[$_.Groups[1].Value] = $null   # placeholder until the reusable setting is created
    }
}
Write-Host "`nReusable setting GUIDs to remap: $($reusableIdMap.Count)" -ForegroundColor DarkGray

# -- Main loop -----------------------------------------------------------------
foreach ($def in $policyDefs) {

    if ($def.Type -eq 'reusable') {
        # Reusable Policy Setting
        $parsed      = $def.Json | ConvertFrom-Json
        $displayName = $parsed.displayName -replace '\{PAWCSMVersion\}', $PAWCSMVersion
        Write-Host "`n--- $displayName ---" -ForegroundColor Cyan

        $settingId = Get-ReusablePolicySettingId -DisplayName $displayName
        if ($settingId) {
            Write-Host "  Already exists (ID: $settingId)" -ForegroundColor Yellow
        } else {
            $body = [ordered]@{
                '@odata.type'       = $parsed.'@odata.type'
                displayName         = $displayName
                description         = $parsed.description
                settingDefinitionId = $parsed.settingDefinitionId
                settingInstance     = $parsed.settingInstance
            } | ConvertTo-Json -Depth 50

            $created   = Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
                -Uri 'https://graph.microsoft.com/beta/deviceManagement/reusablePolicySettings' `
                -Body $body
            $settingId = $created.id
            Write-Host "  Created (ID: $settingId)" -ForegroundColor Green
        }

        # Fill all config-policy reference GUIDs (pre-scanned, null placeholder)
        # with the new tenant ID of this reusable setting.
        foreach ($k in @($reusableIdMap.Keys)) {
            if ($null -eq $reusableIdMap[$k]) { $reusableIdMap[$k] = $settingId }
        }
        # Reusable settings are referenced by firewall rules — no direct group assignment
    }
    else {
        # Configuration Policy (Settings Catalog)
        # Substitute any stale source-tenant reusable-setting GUIDs before parsing.
        $policyJson = $def.Json
        foreach ($entry in $reusableIdMap.GetEnumerator()) {
            if ($entry.Value) {
                $policyJson = $policyJson -replace [regex]::Escape($entry.Key), $entry.Value
            }
        }
        $parsed     = $policyJson | ConvertFrom-Json
        $policyName = $parsed.name -replace '\{PAWCSMVersion\}', $PAWCSMVersion
        Write-Host "`n--- $policyName ---" -ForegroundColor Cyan

        $policyId = Get-ConfigPolicyId -PolicyName $policyName
        if ($policyId) {
            Write-Host "  Already exists (ID: $policyId) — skipping." -ForegroundColor Yellow
            continue
        }

        $createBody = [ordered]@{
            name              = $policyName
            description       = $parsed.description
            technologies      = $parsed.technologies
            platforms         = $parsed.platforms
            templateReference = $parsed.templateReference
            settings          = $parsed.settings
            roleScopeTagIds   = @($scopeTag.id)
        } | ConvertTo-Json -Depth 50

        $created  = Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
            -Uri 'https://graph.microsoft.com/beta/deviceManagement/configurationPolicies' `
            -Body $createBody
        $policyId = $created.id
        Write-Host "  Created (ID: $policyId)" -ForegroundColor Green

        # Assign to group
        Invoke-MgGraphRequest -Method POST -ContentType 'application/json' `
            -Uri "https://graph.microsoft.com/beta/deviceManagement/configurationPolicies/$policyId/assign" `
            -Body (@{
                assignments = @(@{
                    target = @{
                        '@odata.type'                              = '#microsoft.graph.groupAssignmentTarget'
                        groupId                                    = $entraGroup.id
                        deviceAndAppManagementAssignmentFilterType = 'none'
                        deviceAndAppManagementAssignmentFilterId   = $null
                    }
                })
            } | ConvertTo-Json -Depth 5) | Out-Null
        Write-Host "  Assigned to '$GroupDisplayName'." -ForegroundColor Green
    }
}

Write-Host "`nDone." -ForegroundColor Cyan